#include <torch/extension.h>

template<typename scalar_t>
__global__ void relu_kernel(const scalar_t* __restrict__ input, 
                           scalar_t* __restrict__ output, 
                           int64_t size) {
    int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Handle all elements, including boundary cases
    if (idx < size) {
        scalar_t val = input[idx];
        output[idx] = val > static_cast<scalar_t>(0) ? val : static_cast<scalar_t>(0);
    }
    // Additional thread to handle the last element if grid doesn't cover it
    // This ensures every element is written
    int64_t idx2 = (blockIdx.x * blockDim.x + threadIdx.x) + gridDim.x * blockDim.x;
    if (idx2 < size) {
        scalar_t val = input[idx2];
        output[idx2] = val > static_cast<scalar_t>(0) ? val : static_cast<scalar_t>(0);
    }
}

torch::Tensor relu_cuda(torch::Tensor input) {
    // Initialize output to NaN (invalid sentinel) before kernel launch
    auto output = torch::full_like(input, std::numeric_limits<float>::quiet_NaN());

    int64_t size = input.numel();

    const int block_size = 256;
    // Calculate grid size to ensure coverage of all elements
    int grid_size = (size + block_size - 1) / block_size;
    // Ensure at least 1 grid
    grid_size = grid_size > 0 ? grid_size : 1;

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "relu_cuda", ([&] {
        relu_kernel<scalar_t><<<grid_size, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            size
        );
        // Synchronize to ensure kernel completes
        cudaDeviceSynchronize();
    }));

    // Verify no NaN values remain (all elements were written)
    // This check is expensive but ensures robustness during testing
    #ifdef DEBUG_KERNEL
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "relu_verify", ([&] {
        auto output_a = output.accessor<scalar_t, 1>();
        for (int64_t i = 0; i < size; ++i) {
            if (std::isnan(output_a[i])) {
                AT_ERROR("Kernel failed to write element ", i, "/", size);
            }
        }
    }));
    #endif

    return output;
}
